export declare const AzureBlobStorageRules = "\n# Azure Blob Storage - WAF Rules for IaC\n\n- Use zone-redundant storage (ZRS) or geo-redundant storage (GRS/GZRS)\n- Enable soft delete for blobs and containers\n- Enable blob versioning for data protection\n- Disable public blob access unless specifically required\n- Use private endpoints for secure connectivity\n- Enable Azure AD authentication and disable shared key access\n- Use customer-managed keys for encryption at rest\n- Configure firewall rules and virtual network access\n- Configure appropriate storage tier (Hot, Cool, Archive)\n- Enable diagnostic logging to Log Analytics workspace\n";
